module RefModule (
	input clk,
	input rst,
	input d,
	output reg edge_detected);

	reg unused_d_prev;

	always @(posedge clk) begin
		if (rst)
			unused_d_prev <= 0;
		else
			unused_d_prev <= d;
	end

	always @(posedge clk) begin
		if (rst)
			edge_detected <= 0;
		else
			edge_detected <= d & ~unused_d_prev;
	end

endmodule
